css:
.block-cascade-conflict { padding: 24px; background: hsl(var(--bg-surface)); }
.block-cascade-conflict .heading { font-size: 34px; line-height: 1.2; margin: 0; color: hsl(var(--text-primary)); font-family: var(--font-family-headings); }
.block-cascade-conflict .body-text { font-size: 16px; margin: 8px 0 0 0; color: hsl(var(--text-muted)); display: block; }
.block-cascade-conflict .hidden-toggle { display: block; margin-top: 12px; padding: 8px; background: hsl(var(--bg-surface-alt)); }
@container slot (min-width: 768px) { .block-cascade-conflict .heading { font-size: 64px; } }
